def find_target(sr, sc):
    q = deque([(sr, sc, 0)])
    visited = [[-1] * N for _ in range(N)]
    visited[sr][sc] = 0
    candidates = []
    min_dist = float('inf')

    while q:
        r, c, d = q.popleft()
        if d >= min_dist: continue

        for i in range(4):
            nr, nc = r + dr[i], c + dc[i]
            if 0 <= nr < N and 0 <= nc < N and visited[nr][nc] == -1:
                if can_pass(nr, nc):
                    visited[nr][nc] = d + 1
                    if is_target(nr, nc):
                        min_dist = d + 1
                        candidates.append((d+1, nr, nc))
                    q.append((nr, nc, d + 1))

    return sorted(candidates)[0] if candidates else None

