# 전체 90도 회전: (r, c) -> (c, N-1-r)
def rotate_90(grid):
    return [list(row) for row in zip(*grid[::-1])]

# 부분 격자 회전 (r, c 시작, size 크기)
def rotate_sub(r, c, size):
    sub = [row[c:c+size] for row in board[r:r+size]]
    rotated = rotate_90(sub)
    for i in range(size):
        board[r+i][c:c+size] = rotated[i]

