def solve(arr):
    if len(arr) == 1:
        return arr[0]
    best = 0
    for i in range(len(arr)):
        if i == 0:
            score = arr[1]
        elif i == len(arr)-1:
            score = arr[-2]
        else:
            score = arr[i-1] * arr[i+1]
        nxt = arr[:i] + arr[i+1:]
        best = max(best, score + solve(nxt))
    return best

